       wait(tbBusVif.reset_n);
        $display("------[DRIVER]: Reset Ended ------\n");
    endtask;

    task request_thread();
        FLIT_TYPE_t flit_type;
        transaction trans;
        int x,y;
        forever begin
             gen2driv.get(trans);
             x = unsigned'(trans.tg_xaddr);
             y = unsigned'(trans.tg_yaddr);
             pending_q.push_back(trans);
             //`DRIV_IF.tb_flit_request[x][y] <= 0;
